import React, { useState, useEffect } from "react";
import {
  Box,
  Typography,
  Button,
  Avatar,
} from "../ui/material";
import { Wallet, SwapHoriz, TrendingUp, Add, ArrowForward } from "../ui/icons";
import useAllWallets from "../hooks/useAllWallets";
import { getCoinLogo, getCoinFallbackLogo, getCoinDecimalsPlace } from "../components/utils/Chains";
import { getStatusName } from "../components/utils/Display";
import { useHistory } from "react-router-dom";
import { useThemeMode } from "../ui/styles";
import useTransitions from "../hooks/useTransactions";

const WalletIcon = Wallet;
const SwapIcon = SwapHoriz;
const TrendingIcon = TrendingUp;
const AddIcon = Add;
const ArrowIcon = ArrowForward;

const Dashboard = () => {
  const { allWalletInfo, walletBalance } = useAllWallets();
  const [loading, setLoading] = useState(true);
  const { transactions, getTransactions } = useTransitions(null);
  const [txLoading, setTxLoading] = useState(true);
  const history = useHistory();
  const { mode } = useThemeMode();
  const isDark = mode === "dark";

  const handleCoinImageError = (coin) => (event) => {
    event.currentTarget.onerror = null;
    event.currentTarget.src = getCoinFallbackLogo(coin);
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setTxLoading(false);
    }, 1500);
    return () => clearTimeout(timer);
  }, []);

  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Buenos dias";
    if (hour < 18) return "Buenas tardes";
    return "Buenas noches";
  };

  const formatDate = () => {
    return new Date().toLocaleDateString("es-ES", {
      weekday: "long",
      day: "numeric",
      month: "long",
      year: "numeric",
    });
  };

  const getStatusStyle = (status) => {
    const styles = {
      1: { bg: "#FEF3C7", text: "#92400E" },
      2: { bg: "#DBEAFE", text: "#1E40AF" },
      3: { bg: "#D1FAE5", text: "#065F46" },
      4: { bg: "#FEE2E2", text: "#991B1B" },
    };
    return styles[status] || { bg: "#F3F4F6", text: "#6B7280" };
  };

  const getRealDate = (date) => {
    return date?.replace('T', ' ').replace('Z', '').replace(/\.\d+/, "").slice(0, 16);
  };

  if (loading) {
    return (
      <Box style={{ width: "100%", padding: "16px" }}>
        <div style={{ height: "4px", backgroundColor: isDark ? "#2D2D44" : "#E5E7EB", borderRadius: "2px", overflow: "hidden" }}>
          <div style={{ height: "100%", width: "100%", backgroundColor: "#2186EB", animation: "loading 1.5s infinite" }} />
        </div>
        <style>{`@keyframes loading { 0% { width: 0% } 50% { width: 70% } 100% { width: 100% } }`}</style>
      </Box>
    );
  }

  const containerStyle = {
    padding: "32px",
    maxWidth: "1400px",
    margin: "0 auto",
  };

  const headerStyle = {
    marginBottom: "32px",
  };

  const statsGridStyle = {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))",
    gap: "24px",
    marginBottom: "32px",
  };

  const statCardStyle = (color) => ({
    backgroundColor: isDark ? "#1A1A2E" : "#FFFFFF",
    borderRadius: "16px",
    padding: "24px",
    border: `1px solid ${isDark ? "#2D2D44" : "#E5E7EB"}`,
    position: "relative",
    overflow: "hidden",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "flex-start",
  });

  const iconContainerStyle = (color) => ({
    width: "56px",
    height: "56px",
    borderRadius: "12px",
    backgroundColor: `${color}15`,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  });

  const mainGridStyle = {
    display: "grid",
    gridTemplateColumns: "2fr 1fr",
    gap: "24px",
  };

  const sectionStyle = {
    backgroundColor: isDark ? "#1A1A2E" : "#FFFFFF",
    borderRadius: "16px",
    padding: "24px",
    border: `1px solid ${isDark ? "#2D2D44" : "#E5E7EB"}`,
  };

  const walletCardStyle = {
    backgroundColor: isDark ? "#0F0F1A" : "#F9FAFB",
    borderRadius: "12px",
    padding: "16px",
    marginBottom: "12px",
    border: `1px solid ${isDark ? "#2D2D44" : "#E5E7EB"}`,
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    cursor: "pointer",
  };

  const quickActionStyle = (color) => ({
    backgroundColor: "transparent",
    border: `1px solid ${isDark ? "#2D2D44" : "#E5E7EB"}`,
    borderRadius: "12px",
    padding: "16px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    gap: "8px",
    cursor: "pointer",
    marginBottom: "12px",
  });

  const tableStyle = {
    width: "100%",
    borderCollapse: "collapse",
    fontSize: "14px",
  };

  const thStyle = {
    textAlign: "left",
    padding: "12px",
    borderBottom: `2px solid ${isDark ? "#2D2D44" : "#E5E7EB"}`,
    color: isDark ? "#9CA3AF" : "#6B7280",
    fontWeight: 600,
    fontSize: "12px",
  };

  const tdStyle = {
    padding: "12px",
    borderBottom: `1px solid ${isDark ? "#2D2D44" : "#E5E7EB"}`,
    color: isDark ? "#FFFFFF" : "#111827",
  };

  return (
    <div style={containerStyle}>
      {/* Header */}
      <div style={headerStyle}>
        <Typography
          variant="h4"
          style={{ 
            color: isDark ? "#FFFFFF" : "#111827", 
            fontWeight: 700, 
            fontSize: "32px", 
            marginBottom: "8px",
            fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
          }}
        >
          {getGreeting()}!
        </Typography>
        <Typography
          style={{ 
            color: isDark ? "#9CA3AF" : "#6B7280", 
            fontSize: "14px",
            textTransform: "capitalize",
          }}
        >
          {formatDate()}
        </Typography>
      </div>

      {/* Stats Cards */}
      <div style={statsGridStyle}>
        <div style={statCardStyle("#2186EB")}>
          <div>
            <Typography
              style={{ 
                color: isDark ? "#9CA3AF" : "#6B7280", 
                fontSize: "14px", 
                fontWeight: 500,
                marginBottom: "8px",
              }}
            >
              Balance Total
            </Typography>
            <Typography
              style={{ 
                color: isDark ? "#FFFFFF" : "#111827", 
                fontSize: "28px", 
                fontWeight: 700,
              }}
            >
              ${parseFloat(walletBalance || 0).toFixed(2)}
            </Typography>
          </div>
          <div style={iconContainerStyle("#2186EB")}>
            <WalletIcon style={{ color: "#2186EB", fontSize: 24 }} />
          </div>
          <button
            onClick={() => history.push("/wallets")}
            style={{
              position: "absolute",
              bottom: "8px",
              right: "8px",
              background: "none",
              border: "none",
              color: "#2186EB",
              fontSize: "12px",
              cursor: "pointer",
              fontWeight: 500,
            }}
          >
            Ver mas
          </button>
        </div>

        <div style={statCardStyle("#4CAF50")}>
          <div>
            <Typography
              style={{ 
                color: isDark ? "#9CA3AF" : "#6B7280", 
                fontSize: "14px", 
                fontWeight: 500,
                marginBottom: "8px",
              }}
            >
              Billeteras Activas
            </Typography>
            <Typography
              style={{ 
                color: isDark ? "#FFFFFF" : "#111827", 
                fontSize: "28px", 
                fontWeight: 700,
              }}
            >
              {allWalletInfo.length}
            </Typography>
          </div>
          <div style={iconContainerStyle("#4CAF50")}>
            <TrendingIcon style={{ color: "#4CAF50", fontSize: 24 }} />
          </div>
          <button
            onClick={() => history.push("/wallets")}
            style={{
              position: "absolute",
              bottom: "8px",
              right: "8px",
              background: "none",
              border: "none",
              color: "#4CAF50",
              fontSize: "12px",
              cursor: "pointer",
              fontWeight: 500,
            }}
          >
            Ver mas
          </button>
        </div>

        <div style={statCardStyle("#F6851B")}>
          <div>
            <Typography
              style={{ 
                color: isDark ? "#9CA3AF" : "#6B7280", 
                fontSize: "14px", 
                fontWeight: 500,
                marginBottom: "8px",
              }}
            >
              Transacciones Recientes
            </Typography>
            <Typography
              style={{ 
                color: isDark ? "#FFFFFF" : "#111827", 
                fontSize: "28px", 
                fontWeight: 700,
              }}
            >
              {transactions.length}
            </Typography>
          </div>
          <div style={iconContainerStyle("#F6851B")}>
            <SwapIcon style={{ color: "#F6851B", fontSize: 24 }} />
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div style={mainGridStyle}>
        {/* Transactions Section */}
        <div style={sectionStyle}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "20px" }}>
            <Typography
              style={{ 
                color: isDark ? "#FFFFFF" : "#111827", 
                fontSize: "20px", 
                fontWeight: 600,
              }}
            >
              Transacciones Recientes
            </Typography>
          </div>

          {!txLoading ? (
            transactions && transactions.length > 0 ? (
              <table style={tableStyle}>
                <thead>
                  <tr>
                    <th style={thStyle}>Moneda</th>
                    <th style={thStyle}>Tipo</th>
                    <th style={thStyle}>Cantidad</th>
                    <th style={thStyle}>Estado</th>
                    <th style={thStyle}>Fecha</th>
                  </tr>
                </thead>
                <tbody>
                  {transactions.slice(0, 6).map((tx, index) => (
                    <tr 
                      key={index}
                      style={{ cursor: "pointer" }}
                      onClick={() => history.push(`/wallet/${tx.coin.toLowerCase()}`)}
                      onMouseOver={(e) => e.currentTarget.style.backgroundColor = isDark ? "rgba(255,255,255,0.05)" : "rgba(0,0,0,0.02)"}
                      onMouseOut={(e) => e.currentTarget.style.backgroundColor = "transparent"}
                    >
                      <td style={tdStyle}>
                        <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                          <Avatar
                            src={getCoinLogo(tx.coin)}
                            imgProps={{ onError: handleCoinImageError(tx.coin) }}
                            style={{ width: 24, height: 24 }}
                          />
                          <span style={{ fontWeight: 500 }}>{tx.coin.toUpperCase()}</span>
                        </div>
                      </td>
                      <td style={tdStyle}>
                        <span style={{ 
                          color: tx.nature === 1 ? "#10B981" : "#EF4444",
                          fontWeight: 500,
                        }}>
                          {tx.nature === 1 ? "Deposito" : "Retiro"}
                        </span>
                      </td>
                      <td style={tdStyle}>
                        <span style={{ 
                          color: tx.nature === 1 ? "#10B981" : "#EF4444",
                          fontWeight: 600,
                        }}>
                          {tx.nature === 1 && tx.status > 1 ? "+" : ""}
                          {tx.amount ? parseFloat(tx.amount).toFixed(getCoinDecimalsPlace(tx.coin)) : "0"}
                        </span>
                      </td>
                      <td style={tdStyle}>
                        <span style={{
                          padding: "4px 10px",
                          borderRadius: "12px",
                          fontSize: "11px",
                          fontWeight: 500,
                          backgroundColor: getStatusStyle(tx.status).bg,
                          color: getStatusStyle(tx.status).text,
                        }}>
                          {tx.status === 2 && tx.confirmations > 0 
                            ? `${tx.confirmations}/12` 
                            : getStatusName(tx.status)}
                        </span>
                      </td>
                      <td style={{ ...tdStyle, fontSize: "12px", color: isDark ? "#9CA3AF" : "#6B7280" }}>
                        {getRealDate(tx.created_at)}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <div style={{ textAlign: "center", padding: "40px", color: isDark ? "#9CA3AF" : "#6B7280" }}>
                No hay transacciones todavía
              </div>
            )
          ) : (
            <div style={{ textAlign: "center", padding: "40px", color: isDark ? "#9CA3AF" : "#6B7280" }}>
              Cargando transacciones...
            </div>
          )}
        </div>

        {/* Quick Actions Section */}
        <div>
          <div style={sectionStyle}>
            <Typography
              style={{ 
                color: isDark ? "#FFFFFF" : "#111827", 
                fontSize: "20px", 
                fontWeight: 600,
                marginBottom: "16px",
              }}
            >
              Accesos Rapidos
            </Typography>

            <div 
              style={quickActionStyle("#2186EB")}
              onClick={() => history.push("/wallets")}
            >
              <AddIcon style={{ color: "#2186EB", fontSize: 24 }} />
              <Typography style={{ fontSize: "12px", fontWeight: 500, color: isDark ? "#FFFFFF" : "#111827" }}>
                Nueva Billetera
              </Typography>
            </div>

            <div 
              style={quickActionStyle("#4CAF50")}
              onClick={() => history.push("/wallets")}
            >
              <WalletIcon style={{ color: "#4CAF50", fontSize: 24 }} />
              <Typography style={{ fontSize: "12px", fontWeight: 500, color: isDark ? "#FFFFFF" : "#111827" }}>
                Ver Todas
              </Typography>
            </div>

            <div 
              style={quickActionStyle("#F6851B")}
              onClick={() => history.push("/providers")}
            >
              <SwapIcon style={{ color: "#F6851B", fontSize: 24 }} />
              <Typography style={{ fontSize: "12px", fontWeight: 500, color: isDark ? "#FFFFFF" : "#111827" }}>
                Vender P2P
              </Typography>
            </div>
          </div>

          {/* Support Card */}
          <div style={{
            ...sectionStyle,
            marginTop: "16px",
            background: "linear-gradient(135deg, #2186EB 0%, #1A6BC7 100%)",
          }}>
            <Typography
              style={{ 
                color: "white", 
                fontSize: "18px", 
                fontWeight: 600,
                marginBottom: "8px",
              }}
            >
              Necesitas ayuda?
            </Typography>
            <Typography
              style={{ 
                color: "rgba(255,255,255,0.8)", 
                fontSize: "14px",
                marginBottom: "16px",
              }}
            >
              Nuestro equipo de soporte esta disponible 24/7
            </Typography>
            <Button
              onClick={() => history.push("/welcome")}
              style={{
                backgroundColor: "white",
                color: "#2186EB",
                borderRadius: "12px",
                textTransform: "none",
                fontWeight: 600,
                padding: "12px 24px",
                border: "none",
                cursor: "pointer",
              }}
            >
              Contactar Soporte
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;