import React from 'react';
import { Typography, Box, Avatar } from '../ui/material';
import { getDisplayableTxHash, getStatusName } from './utils/Display';
import {
    getCoinDecimalsPlace,
    getCoinFee,
    getCoinLogo,
    getNetworkExplorerBase,
    getNetworkName,
    getCoinFallbackLogo
} from './utils/Chains';
import CopyToClipboard from 'react-copy-to-clipboard';
import { useThemeMode } from '../ui/styles';

export default function CoinTransactions({ transactions, coin, chainId }) {
    const { mode } = useThemeMode();
    const isDark = mode === 'dark';
    const [copied, setCopied] = React.useState(false);
    const [txCopied, setTxCopied] = React.useState(false);
    const [selectedTransaction, setSelectedTransaction] = React.useState(null);

    const styles = {
        container: {
            backgroundColor: isDark ? "#1A1A2E" : "#FFFFFF",
            borderRadius: "16px",
            padding: "20px",
            border: `1px solid ${isDark ? "#2D2D44" : "#E5E7EB"}`,
            overflowX: "auto",
        },
        title: {
            color: isDark ? "#FFFFFF" : "#1A1A2E",
            fontSize: "18px",
            fontWeight: 600,
            marginBottom: "16px",
        },
        table: {
            width: "100%",
            borderCollapse: "collapse",
            fontSize: "14px",
        },
        th: {
            textAlign: "left",
            padding: "12px",
            borderBottom: `2px solid ${isDark ? "#2D2D44" : "#E5E7EB"}`,
            color: isDark ? "#9CA3AF" : "#6B7280",
            fontWeight: 600,
        },
        td: {
            padding: "12px",
            borderBottom: `1px solid ${isDark ? "#2D2D44" : "#E5E7EB"}`,
            color: isDark ? "#FFFFFF" : "#1A1A2E",
        },
        statusBadge: (status) => {
            const colors = {
                1: { bg: "#FEF3C7", text: "#92400E" },
                2: { bg: "#DBEAFE", text: "#1E40AF" },
                3: { bg: "#D1FAE5", text: "#065F46" },
                4: { bg: "#FEE2E2", text: "#991B1B" },
            };
            return colors[status] || { bg: "#F3F4F6", text: "#6B7280" };
        },
        amount: (nature) => ({
            color: nature === 1 ? "#10B981" : "#EF4444",
            fontWeight: 600,
        }),
        dialog: {
            position: "fixed",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: "rgba(0,0,0,0.5)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 100,
        },
        dialogContent: {
            backgroundColor: isDark ? "#1A1A2E" : "#FFFFFF",
            borderRadius: "16px",
            padding: "24px",
            maxWidth: "500px",
            width: "90%",
            maxHeight: "80vh",
            overflowY: "auto",
        },
        label: {
            color: isDark ? "#9CA3AF" : "#6B7280",
            fontSize: "12px",
            marginBottom: "4px",
        },
        value: {
            color: isDark ? "#FFFFFF" : "#1A1A2E",
            fontSize: "14px",
            fontWeight: 500,
        },
    };

    const getRealDate = (date) => {
        return date?.replace('T', ' ').replace('Z', '').replace(/\.\d+/, "");
    };

    const handleOpen = (transaction) => {
        setSelectedTransaction(transaction);
    };

    const handleClose = () => {
        setSelectedTransaction(null);
    };

    if (!transactions || transactions.length === 0) {
        return (
            <div style={styles.container}>
                <div style={styles.title}>Historial de transacciones</div>
                <div style={{ textAlign: "center", padding: "40px", color: isDark ? "#9CA3AF" : "#6B7280" }}>
                    No hay transacciones todavía
                </div>
            </div>
        );
    }

    return (
        <>
            <div style={styles.container}>
                <div style={styles.title}>Historial de transacciones</div>
                <table style={styles.table}>
                    <thead>
                        <tr>
                            <th style={styles.th}>ID Transaccion</th>
                            <th style={styles.th}>Cantidad</th>
                            <th style={styles.th}>Estado</th>
                            <th style={styles.th}>Fecha</th>
                        </tr>
                    </thead>
                    <tbody>
                        {transactions.map((transaction) => (
                            <tr 
                                key={transaction.txHash} 
                                style={{ cursor: "pointer" }}
                                onClick={() => handleOpen(transaction)}
                                onMouseOver={(e) => e.currentTarget.style.backgroundColor = isDark ? "rgba(255,255,255,0.05)" : "rgba(0,0,0,0.02)"}
                                onMouseOut={(e) => e.currentTarget.style.backgroundColor = "transparent"}
                            >
                                <td style={styles.td}>
                                    <span style={{ color: "#2186EB" }}>
                                        {getDisplayableTxHash(transaction.txHash)}
                                    </span>
                                </td>
                                <td style={styles.td}>
                                    <span style={styles.amount(transaction.nature)}>
                                        {transaction.nature === 1 && transaction.status > 1 ? '+' : ''}
                                        {transaction.amount ? parseFloat(transaction.amount).toFixed(getCoinDecimalsPlace(coin)) : ''}
                                    </span>
                                </td>
                                <td style={styles.td}>
                                    <span style={{
                                        padding: "4px 12px",
                                        borderRadius: "20px",
                                        fontSize: "12px",
                                        fontWeight: 500,
                                        backgroundColor: styles.statusBadge(transaction.status).bg,
                                        color: styles.statusBadge(transaction.status).text,
                                    }}>
                                        {transaction.status === 2 && transaction.confirmations > 0 
                                            ? `Confirmacion ${transaction.confirmations}/12` 
                                            : getStatusName(transaction.status)}
                                    </span>
                                </td>
                                <td style={styles.td}>
                                    {getRealDate(transaction.created_at)}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Dialog */}
            {selectedTransaction && (
                <div style={styles.dialog} onClick={handleClose}>
                    <div style={styles.dialogContent} onClick={(e) => e.stopPropagation()}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "20px" }}>
                            <div style={{ color: isDark ? "#FFFFFF" : "#1A1A2E", fontSize: "20px", fontWeight: 600 }}>
                                Detalles de {selectedTransaction.nature === 1 ? 'Deposito' : 'Retiro'}
                            </div>
                            <button 
                                onClick={handleClose}
                                style={{
                                    background: "none",
                                    border: "none",
                                    fontSize: "24px",
                                    cursor: "pointer",
                                    color: isDark ? "#9CA3AF" : "#6B7280",
                                }}
                            >
                                x
                            </button>
                        </div>

                        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "16px" }}>
                            <div>
                                <div style={styles.label}>Estado</div>
                                <div style={{ ...styles.value, color: styles.statusBadge(selectedTransaction.status).text }}>
                                    {getStatusName(selectedTransaction.status)}
                                </div>
                            </div>
                            <div>
                                <div style={styles.label}>Fecha</div>
                                <div style={styles.value}>{getRealDate(selectedTransaction.created_at)}</div>
                            </div>
                            <div>
                                <div style={styles.label}>Moneda</div>
                                <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                                    <Avatar 
                                        src={getCoinLogo(coin)}
                                        imgProps={{ onError: (e) => { e.currentTarget.src = getCoinFallbackLogo(coin); } }}
                                        style={{ width: 24, height: 24 }}
                                    />
                                    <span style={styles.value}>{coin.toUpperCase()}</span>
                                </div>
                            </div>
                            <div>
                                <div style={styles.label}>Cantidad</div>
                                <div style={styles.value}>
                                    {selectedTransaction.nature === 1 
                                        ? parseFloat(selectedTransaction.amount).toFixed(getCoinDecimalsPlace(coin))
                                        : -1 * parseFloat(Math.abs(selectedTransaction.amount) - getCoinFee(coin)).toFixed(getCoinDecimalsPlace(coin))}
                                </div>
                            </div>
                            <div>
                                <div style={styles.label}>Red</div>
                                <div style={styles.value}>{getNetworkName(chainId)}</div>
                            </div>
                            {selectedTransaction.nature === 2 && (
                                <div>
                                    <div style={styles.label}>Comision</div>
                                    <div style={styles.value}>{getCoinFee(coin)} {coin.toUpperCase()}</div>
                                </div>
                            )}
                        </div>

                        {selectedTransaction.nature === 2 && (
                            <div style={{ marginTop: "16px" }}>
                                <div style={styles.label}>Direccion</div>
                                <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                                    <span style={{ ...styles.value, fontFamily: "monospace", fontSize: "12px", flex: 1, overflow: "hidden", textOverflow: "ellipsis" }}>
                                        {selectedTransaction.to}
                                    </span>
                                    <CopyToClipboard
                                        text={selectedTransaction.to}
                                        onCopy={() => { setCopied(true); setTimeout(() => setCopied(false), 2000); }}
                                    >
                                        <button style={{
                                            padding: "8px",
                                            borderRadius: "8px",
                                            border: "none",
                                            backgroundColor: isDark ? "#2D2D44" : "#F3F4F6",
                                            cursor: "pointer",
                                        }}>
                                            {copied ? "✓" : "📋"}
                                        </button>
                                    </CopyToClipboard>
                                </div>
                            </div>
                        )}

                        {selectedTransaction.status > 1 && (
                            <div style={{ marginTop: "16px" }}>
                                <div style={styles.label}>TxID</div>
                                <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                                    <span style={{ ...styles.value, fontFamily: "monospace", fontSize: "12px", flex: 1, overflow: "hidden", textOverflow: "ellipsis" }}>
                                        {`${selectedTransaction.txHash.slice(0, 20)}...`}
                                    </span>
                                    <CopyToClipboard
                                        text={selectedTransaction.txHash}
                                        onCopy={() => { setTxCopied(true); setTimeout(() => setTxCopied(false), 2000); }}
                                    >
                                        <button style={{
                                            padding: "8px",
                                            borderRadius: "8px",
                                            border: "none",
                                            backgroundColor: isDark ? "#2D2D44" : "#F3F4F6",
                                            cursor: "pointer",
                                        }}>
                                            {txCopied ? "✓" : "📋"}
                                        </button>
                                    </CopyToClipboard>
                                </div>
                            </div>
                        )}

                        <button 
                            onClick={handleClose}
                            style={{
                                width: "100%",
                                marginTop: "24px",
                                padding: "14px",
                                backgroundColor: "#2186EB",
                                color: "white",
                                border: "none",
                                borderRadius: "12px",
                                fontSize: "14px",
                                fontWeight: 600,
                                cursor: "pointer",
                            }}
                        >
                            Cerrar
                        </button>
                    </div>
                </div>
            )}
        </>
    );
}